// Redis connection
let redisClient: Redis | null = null

export const getRedisClient = (): Redis => {
  if (!redisClient) {
    // Strip query params (e.g. ?family=0) from Railway Redis URLs then pass
    // family: 0 as a number. Node.js v20+ rejects the string '0' from URL query
    // params; numeric 0 enables dual-stack DNS required on Railway's internal network.
    const redisUrl = config.REDIS_URL?.split('?')[0]
    redisClient = new Redis(redisUrl, {
      family: 0,
      maxRetriesPerRequest: 3,
      enableReadyCheck: false,
      lazyConnect: true
    })

    redisClient.on('connect', () => {
      logger.info('Redis connected')
    })

    redisClient.on('error', (error) => {
      logger.error('Redis connection error', error)
    })

    redisClient.on('ready', () => {
      logger.info('Redis ready')
    })
  }

  return redisClient
}

